// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const [expandedForecastIndex, setExpandedForecastIndex] = useState<number | null>(null);

  const getWeatherEmoji = useCallback((condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')) return '☁️';
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('windy') || lowerCondition.includes('wind')) return '💨';
    if (lowerCondition.includes('foggy') || lowerCondition.includes('fog')) return '🌫️';
    if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
    return '🌤️';
  }, []);

  return {
    expandedForecastIndex,
    setExpandedForecastIndex,
    getWeatherEmoji,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* Header with location */}
        <Stack gap={8} align="center">
          <Heading level={1} align="center">{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
            Current Weather
          </Text>
        </Stack>

        {/* Main weather card */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24} align="center">
            {/* Temperature and condition row */}
            <Stack gap={16} align="center" justify="center">
              <Box
                style={{
                  fontSize: '72px',
                  lineHeight: '1',
                }}>
                {state.getWeatherEmoji(props.condition)}
              </Box>
              <Stack gap={4} align="center">
                <Heading
                  level={2}
                  align="center"
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 36px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  }}>
                  {props.temperature}°{props.unit}
                </Heading>
                <Text
                  variant="bodyLarge"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            {/* Divider */}
            <Divider margin={0} />

            {/* Humidity and Wind row */}
            <Row gap={24} align="center" justify="center" wrap>
              <Stack gap={8} align="center">
                <Text
                  variant="overline"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Heading
                  level={5}
                  color="var(--ggui-color-primary-600, #0284c7)">
                  {props.humidity}%
                </Heading>
              </Stack>

              <Stack gap={8} align="center">
                <Text
                  variant="overline"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Heading
                  level={5}
                  color="var(--ggui-color-primary-600, #0284c7)">
                  {props.windSpeed} m/s
                </Heading>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast strip */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap={12}>
            <Heading level={3}>5-Day Forecast</Heading>
            <Row gap={8} align="center" justify="start" wrap>
              {props.forecast.map((day, index) => (
                <Box
                  key={index}
                  style={{
                    flex: '0 0 auto',
                    minWidth: '100px',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    textAlign: 'center',
                    cursor: 'pointer',
                    transition: 'all 200ms ease-in-out',
                  }}
                  as={Clickable}
                  onClick={() =>
                    state.setExpandedForecastIndex(
                      state.expandedForecastIndex === index ? null : index
                    )
                  }>
                  <Stack gap={6} align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurface, #18181b)"
                      style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}>
                      {day.day || `Day ${index + 1}`}
                    </Text>
                    <Box style={{ fontSize: '20px', lineHeight: '1' }}>
                      {day.icon || state.getWeatherEmoji(day.day || '')}
                    </Box>
                    <Stack direction="horizontal" gap={2} align="center">
                      <Text
                        variant="caption"
                        color="var(--ggui-color-primary-600, #0284c7)"
                        style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}>
                        H: {day.high}°{props.unit}
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}>
                        L: {day.low}°{props.unit}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit?: (payload: ActionSubmitPayload) => void; // Callback when survey is submitted
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // State: multi-step form
  const [state, setState] = useState({
    currentStep: 1,
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });

  // Validation
  const isValidEmail = useCallback((value: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  }, []);

  const isStep1Valid = useCallback(() => {
    return state.name.trim() !== '' && state.email.trim() !== '' && isValidEmail(state.email);
  }, [state.name, state.email, isValidEmail]);

  const isStep2Valid = useCallback(() => {
    return state.satisfaction !== '';
  }, [state.satisfaction]);

  const isStep3Valid = useCallback(() => {
    // Features are optional, so always valid
    return true;
  }, []);

  const isCurrentStepValid = useCallback(() => {
    if (state.currentStep === 1) return isStep1Valid();
    if (state.currentStep === 2) return isStep2Valid();
    if (state.currentStep === 3) return isStep3Valid();
    return true; // Step 4 (comments) is optional, Step 5 is review
  }, [state.currentStep, isStep1Valid, isStep2Valid, isStep3Valid]);

  const handleNext = useCallback(() => {
    if (isCurrentStepValid()) {
      if (state.currentStep < 5) {
        setState(prev => ({ ...prev, currentStep: prev.currentStep + 1 }));
      }
    }
  }, [state.currentStep, isCurrentStepValid]);

  const handleBack = useCallback(() => {
    if (state.currentStep > 1) {
      setState(prev => ({ ...prev, currentStep: prev.currentStep - 1 }));
    }
  }, [state.currentStep]);

  const handleSubmit = useCallback(() => {
    if (isStep1Valid() && isStep2Valid()) {
      const payload: ActionSubmitPayload = {
        name: state.name.trim(),
        email: state.email.trim(),
        satisfaction: parseInt(state.satisfaction, 10),
        features: state.features,
        comments: state.comments.trim()
      };
      // Call onSubmit from props
      if (props.onSubmit) {
        props.onSubmit(payload);
      }
    }
  }, [state.name, state.email, state.satisfaction, state.features, state.comments, isStep1Valid, isStep2Valid, props]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setState(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  }, []);

  return {
    state,
    setState,
    isValidEmail,
    isStep1Valid,
    isStep2Valid,
    isStep3Valid,
    isCurrentStepValid,
    handleNext,
    handleBack,
    handleSubmit,
    handleFeatureToggle
  };
}

export default function Component(props: Props) {
  const hook = useComponent(props);
  const { state, isValidEmail } = hook;

  const emailError = state.email && !isValidEmail(state.email) ? 'Please enter a valid email address' : '';
  const nameError = state.name === '' && state.currentStep >= 1 ? 'Name is required' : '';

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Progress Bar */}
        <Box paddingY="var(--ggui-spacing-2, 8px)">
          <Stack gap="var(--ggui-spacing-2, 8px)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {state.currentStep} of 5
              </Text>
              {state.currentStep === 5 && (
                <Badge variant="success" size="sm">
                  Review
                </Badge>
              )}
            </Row>
            <Progress
              value={state.currentStep}
              max={5}
              variant={state.currentStep === 5 ? 'success' : 'default'}
              size="md"
            />
          </Stack>
        </Box>

        {/* Step 1: Name & Email */}
        {state.currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                About You
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please provide your basic information
              </Text>
              <Divider margin="var(--ggui-spacing-2, 8px)" />
              <Input
                label="Name"
                placeholder="Enter your full name"
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={state.name}
                onChange={(value) => hook.setState(prev => ({ ...prev, name: value }))}
                error={nameError}
                required
              />
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email address"
                value={state.email}
                onChange={(value) => hook.setState(prev => ({ ...prev, email: value }))}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {state.currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                How satisfied are you?
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please rate your satisfaction level
              </Text>
              <Divider margin="var(--ggui-spacing-2, 8px)" />
              <RadioGroup
                label="Satisfaction Rating"
                value={state.satisfaction}
                onChange={(value) => hook.setState(prev => ({ ...prev, satisfaction: value }))}
                options={(props.satisfactionLabels || []).map((label, index) => ({
                  value: String(index + 1),
                  label: label
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {state.currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Which features interest you?
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select all that apply
              </Text>
              <Divider margin="var(--ggui-spacing-2, 8px)" />
              <Stack gap="var(--ggui-spacing-2, 8px)">
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={() => hook.handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {state.currentStep === 4 && (
          <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Additional Comments
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Share any additional feedback (optional)
              </Text>
              <Divider margin="var(--ggui-spacing-2, 8px)" />
              <TextArea
                label="Comments"
                placeholder="Enter your comments here..."
                value={state.comments}
                onChange={(value) => hook.setState(prev => ({ ...prev, comments: value }))}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {state.currentStep === 5 && (
          <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Review Your Answers
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please verify your information before submitting
              </Text>
              <Divider margin="var(--ggui-spacing-2, 8px)" />

              {/* Review items */}
              <Box paddingY="var(--ggui-spacing-4, 16px)" paddingX="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                <Stack gap="var(--ggui-spacing-3, 12px)">
                  <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', justifyContent: 'space-between' }}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Name:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                      {state.name}
                    </Text>
                  </div>
                  <Divider margin="var(--ggui-spacing-1, 4px)" />
                  <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', justifyContent: 'space-between' }}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Email:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                      {state.email}
                    </Text>
                  </div>
                  <Divider margin="var(--ggui-spacing-1, 4px)" />
                  <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', justifyContent: 'space-between' }}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Satisfaction:
                    <Badge variant="primary" size="sm">
                      {state.satisfaction ? ((props.satisfactionLabels || [])[parseInt(state.satisfaction, 10) - 1] || 'Unknown') : 'Not selected'}
                    </Badge>
                  </div>
                  <Divider margin="var(--ggui-spacing-1, 4px)" />
                  <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', flexDirection: 'column' }}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Features Selected:
                    </Text>
                    <Stack gap="var(--ggui-spacing-1, 4px)" direction="horizontal" wrap>
                      {state.features.map((feature) => (
                        <Badge key={feature} variant="secondary" size="sm">
                          {feature}
                        </Badge>
                      ))}
                    </Stack>
                  </div>
                  {state.comments && (
                    <>
                      <Divider margin="var(--ggui-spacing-1, 4px)" />
                      <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', flexDirection: 'column' }}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Comments:
                        </Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                          {state.comments}
                        </Text>
                      </div>
                    </>
                  )}
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-2, 8px)" justify="between" align="center">
          <Button
            variant="outline"
            onClick={hook.handleBack}
            disabled={state.currentStep === 1}
            disabled={state.currentStep === 1}
          >
            ← Back
          </Button>
          <Spacer size="flex" />
          {state.currentStep < 5 && (
            <Button
              variant="primary"
              onClick={hook.handleNext}
              disabled={!hook.isCurrentStepValid()}
            >
              Next →
            </Button>
          )}
          {state.currentStep === 5 && (
            <Button
              variant="primary"
              onClick={hook.handleSubmit}
            >
              Submit Survey
            </Button>
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useEffect } from 'react';
import { Container, Card, Stack, Box, Divider, Text, Heading, Button, Input, Select, Badge, Spinner, Avatar, Progress, Icon } from '@ggui-ai/design/primitives';
import { Dropdown } from '@ggui-ai/design/components';
import { Clickable, Hoverable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const fireTaskUpdate = (payload: ActionTaskUpdatePayload) => {
    window.dispatchEvent(new CustomEvent('ggui:action-taskUpdate', { detail: payload }));
  };

  // Streams — listen for real-time updates
  const [streamEvent, setStreamEvent] = useState<StreamTaskChanged | null>(null);

  // Local state
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  // Listen for stream events from agent
  useEffect(() => {
    const handler = (evt: Event) => {
      const customEvt = evt as CustomEvent<StreamTaskChanged>;
      setStreamEvent(customEvt.detail);
    };
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  // Apply stream updates to local tasks
  useEffect(() => {
    if (streamEvent?.task) {
      const updatedTask = streamEvent.task;
      setTasks((prevTasks) => {
        const existing = prevTasks.findIndex((t) => t.id === updatedTask.id);
        if (streamEvent?.action === 'delete' && existing >= 0) {
          return prevTasks.filter((_, i) => i !== existing);
        }
        if (existing >= 0) {
          const newTasks = [...prevTasks];
          newTasks[existing] = { ...newTasks[existing], ...updatedTask };
          return newTasks;
        }
        if (streamEvent?.action === 'create') {
          return [...prevTasks, updatedTask];
        }
        return prevTasks;
      });
    }
  }, [streamEvent]);

  // Computed: group tasks by column
  const tasksByColumn = React.useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns.forEach((col) => {
      grouped[col.id!] = [];
    });
    tasks.forEach((task) => {
      const col = task.column || 'todo';
      if (grouped[col]) {
        grouped[col].push(task);
      }
    });
    return grouped;
  }, [tasks, props.columns]);

  // Computed: summary stats
  const stats = React.useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [tasks]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks((prevTasks) =>
      prevTasks.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t))
    );
    fireTaskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, []);

  const handleStartEdit = useCallback((task: (typeof tasks)[0]) => {
    setEditingTaskId(task.id!);
    setEditingTitle(task.title || '');
  }, []);

  const handleSaveEdit = useCallback((taskId: string) => {
    setTasks((prevTasks) =>
      prevTasks.map((t) => (t.id === taskId ? { ...t, title: editingTitle } : t))
    );
    fireTaskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
    setEditingTaskId(null);
  }, [editingTitle, tasks]);

  const handleAddTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newId = `task-${Date.now()}`;
    const newTask = {
      id: newId,
      title: newTaskTitle,
      priority: newTaskPriority as 'low' | 'medium' | 'high',
      assignee: '',
      column: columnId,
      dueDate: '',
    };
    setTasks((prev) => [...prev, newTask]);
    fireTaskUpdate({ action: 'create', taskId: newId, data: { column: columnId } });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId(null);
  }, [newTaskTitle, newTaskPriority]);
