function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const seen = new Set<string>();
    const result: { category: string; color: string }[] = [];
    const categoryColors: Record<string, string> = {
      'nonmetal': 'var(--ggui-color-info-100, #cffafe)',
      'noble-gas': 'var(--ggui-color-success-100, #dcfce7)',
      'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
      'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'transition-metal': 'var(--ggui-color-primary-200, #bae6fd)',
      'semimetal': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      'lanthanide': 'var(--ggui-color-info-50, #ecfeff)',
      'actinide': 'var(--ggui-color-warning-50, #fffbeb)',
    };
    props.elements.forEach(el => {
      if (el.category && !seen.has(el.category)) {
        seen.add(el.category);
        result.push({
          category: el.category,
          color: categoryColors[el.category] || 'var(--ggui-color-surface, #ffffff)',
        });
      }
    });
    return result;
  }, [props.elements]);

  // Get color for a category
  const getCategoryColor = useCallback((category?: string): string => {
    const categoryColors: Record<string, string> = {
      'nonmetal': 'var(--ggui-color-info-100, #cffafe)',
      'noble-gas': 'var(--ggui-color-success-100, #dcfce7)',
      'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
      'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'transition-metal': 'var(--ggui-color-primary-200, #bae6fd)',
      'semimetal': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      'lanthanide': 'var(--ggui-color-info-50, #ecfeff)',
      'actinide': 'var(--ggui-color-warning-50, #fffbeb)',
    };
    return categoryColors[category || ''] || 'var(--ggui-color-surface, #ffffff)';
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryColor,
  };
}

