function useComponent(props: Props) {
  // Manual wire for actions and streams since useAction/useStream are not exported
  // We'll handle the stream listener in the component

  // State for composing and displaying messages
  const [allMessages, setAllMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  // Track active typists as a map of sender -> true (to support multiple simultaneous typists)
  const [activeTypists, setActiveTypists] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Send message handler
  const sendMessage = useCallback((payload: ActionSendMessagePayload) => {
    if (inputValue.trim()) {
      // Dispatch to agent via window event
      window.dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'sendMessage', payload } }));
      setInputValue('');
    }
  }, [inputValue]);

  // Handle Enter key in input
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      if (inputValue.trim()) {
        const now = new Date().toISOString();
        sendMessage({ text: inputValue, timestamp: now });
      }
    }
  }, [inputValue, sendMessage]);

  // Handle send button click
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const now = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp: now });
    }
  }, [inputValue, sendMessage]);

  // Listen for stream events
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data.stream === 'message' && data.event) {
        // Append new message to list
        setAllMessages(prev => [...prev, data.event]);
        // Auto-scroll to bottom
        setTimeout(() => {
          messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }, 0);
      }
      if (data.stream === 'typing' && data.event) {
        // Update typing indicator: track active typists per sender
        const sender = data.event.sender ?? '';
        const active = data.event.active ?? false;
        setActiveTypists(prev => {
          const updated = { ...prev };
          if (active) {
            // Add this sender to active typists
            updated[sender] = true;
          } else {
            // Remove this sender from active typists
            delete updated[sender];
          }
          return updated;
        });
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Get list of currently typing senders
  const typingSenders = Object.keys(activeTypists).filter(sender => activeTypists[sender]);

  return {
    allMessages,
    setAllMessages,
    inputValue,
    setInputValue,
    handleSendMessage,
    handleKeyDown,
    typingSenders,
    messagesEndRef,
  };
