// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdatedTime, setLastUpdatedTime] = useState(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const [marketStatus, setMarketStatus] = useState<'open' | 'closed' | 'pre-market' | 'after-hours'>('closed');
  const highlightTimeoutRef = useRef<{ [key: string]: NodeJS.Timeout }>({});

  // Listen for ggui:agent-data stream events (priceUpdate and marketStatus)
  useEffect(() => {
    const handleStreamData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { stream, data } = customEvent.detail;

      // Handle price update events
      if (stream === 'priceUpdate' && data) {
        const update = data as StreamPriceUpdate;
        setStocks((prevStocks) =>
          prevStocks.map((stock) =>
            stock.symbol === update.symbol
              ? { ...stock, price: update.price ?? stock.price, change: update.change ?? stock.change, changePercent: update.changePercent ?? stock.changePercent }
              : stock
          )
        );
        setLastUpdatedTime(new Date());

        // Highlight the updated stock
        if (update.symbol) {
          setHighlightedSymbols((prev) => new Set([...prev, update.symbol]));
          // Clear previous timeout if exists
          if (highlightTimeoutRef.current[update.symbol]) {
            clearTimeout(highlightTimeoutRef.current[update.symbol]);
          }
          // Remove highlight after 600ms
          highlightTimeoutRef.current[update.symbol] = setTimeout(() => {
            setHighlightedSymbols((prev) => {
              const next = new Set(prev);
              next.delete(update.symbol!);
              return next;
            });
          }, 600);
        }
      }

      // Handle market status events
      if (stream === 'marketStatus' && data) {
        const statusUpdate = data as StreamMarketStatus;
        if (statusUpdate.status) {
          setMarketStatus(statusUpdate.status);
          setLastUpdatedTime(new Date());
        }
      }
    };
    window.addEventListener('ggui:agent-data', handleStreamData);
    return () => {
      window.removeEventListener('ggui:agent-data', handleStreamData);
    };
  }, []);

  return { stocks, lastUpdatedTime, highlightedSymbols, marketStatus };

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* Header with title and last updated timestamp */}
        <Box>
          <Stack gap={12} align="center" justify="between" direction="horizontal">
            <Stack gap={8} align="center">
              <Heading level={1}>Market Watch</Heading>
              <Badge variant={state.marketStatus === 'open' ? 'success' : state.marketStatus === 'pre-market' ? 'warning' : state.marketStatus === 'after-hours' ? 'info' : 'default'} size="sm">{state.marketStatus.charAt(0).toUpperCase() + state.marketStatus.slice(1).replace('-', ' ')}</Badge>
            </Stack>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {state.lastUpdatedTime.toLocaleTimeString()}
            </Text>
          </Stack>
        </Box>

         {/* Stock grid */}

        {/* Responsive grid of stock cards */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {state.stocks.map((stock) => {
            const isPositive = (stock.changePercent ?? 0) >= 0;
            const isHighlighted = state.highlightedSymbols.has(stock.symbol ?? '');
            const textColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const borderColor = isPositive
              ? 'var(--ggui-color-success-200, #bbf7d0)'
              : 'var(--ggui-color-error-200, #fecaca)';

            return (
              <Card
                key={stock.symbol}
                padding={16}
                radius="lg"
                shadow="sm"
                style={
                  isHighlighted
                    ? {
                        borderColor: borderColor,
                        borderWidth: '2px',
                        animation: 'ggui-flash 600ms ease-out',
                      }
                    : {
                        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                        borderWidth: '1px',
                      }
                }
              >
                <Stack gap={12}>
                  {/* Stock Symbol - Large and Bold */}
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                    {stock.symbol}
                  </Heading>

                  {/* Company Name */}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {stock.name}
                  </Text>

                  {/* Current Price */}
                  <Text variant="body" size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>

                  {/* Change Amount and Percentage with Arrow */}
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="body" weight="semibold" color={textColor}>
                      {isPositive ? '▲' : '▼'} {Math.abs(stock.change ?? 0).toFixed(2)}
                    </Text>
                    <Text variant="body" weight="semibold" color={textColor}>
                      {isPositive ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}%
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
      <style>{`
        @keyframes ggui-flash {
          0% { background-color: var(--ggui-color-primary-50, #f0f9ff); }
          100% { background-color: var(--ggui-color-surface, #fafafa); }
        }
      `}</style>
    </Container>
  );
}

